import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onSuccess, onClose }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({ 
    title: '', location: '', startDate: '', endDate: '', 
    description: '', importantNotes: '', capacity: '', 
    price: '', discount: '', status: 'Available'
  });

  // 圖片狀態
  const [imageFile, setImageFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);

  useEffect(() => {
    if (editingTour) {
      setFormData({ ...editingTour });
      setPreviewUrl(editingTour.imageUrl);
    }
  }, [editingTour]);

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImageFile(file);
      setPreviewUrl(URL.createObjectURL(file)); // 顯示本地預覽圖
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const data = new FormData();
      // 將所有文字欄位放入 FormData
      Object.keys(formData).forEach(key => {
        if (!['_id', '__v', 'createdAt', 'updatedAt'].includes(key)) {
          data.append(key, formData[key]);
        }
      });
      // 放入圖片檔案
      if (imageFile) data.append('image', imageFile);

      const config = {
        headers: { 
          Authorization: `Bearer ${user.token}`,
          'Content-Type': 'multipart/form-data' // 👈 告訴後端這是檔案
        }
      };

      if (editingTour) {
        await axiosInstance.put(`/api/tours/${editingTour._id}`, data, config);
      } else {
        await axiosInstance.post('/api/tours', data, config);
      }
      onSuccess();
    } catch (err) { alert('Upload failed'); }
  };

  return (
    <div className="bg-white min-h-screen p-6">
      {/* ... Header 保持不變 ... */}
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* 其他欄位保持不變 ... */}

        {/* 圖片上傳區塊 */}
        <div className="space-y-2">
          <label className="text-xs font-black text-gray-400 uppercase">Upload cover picture</label>
          <label className="block border-2 border-dashed border-gray-100 rounded-[32px] p-6 bg-gray-50 cursor-pointer text-center">
            {previewUrl ? (
              <img src={previewUrl} className="w-full h-40 object-cover rounded-2xl mb-2" alt="Preview" />
            ) : (
              <div className="py-4">
                <span className="text-4xl text-gray-300">☁️</span>
                <p className="font-bold text-gray-700 mt-2">Click to upload cover picture</p>
              </div>
            )}
            <input type="file" className="hidden" onChange={handleFileChange} accept="image/*" />
          </label>
        </div>

        <button type="submit" className="w-full bg-emerald-500 text-white font-bold py-5 rounded-[24px]">
          Submit
        </button>
      </form>
    </div>
  );
};

export default TourForm;
